// Internal canonical: feelingNormalized 0..23
function normalizeFeeling(raw, gen) {
  return gen === 8 ? raw - 1 : raw;
}

function exportFeeling(normalized, gen) {
  return gen === 8 ? normalized + 1 : normalized;
}

// Gen 8: feeling 0 is empty/invalid
// Bank/HOME transfer bug: Gen 6 feelings may display wrong on SWSH without fixup

function chooseFeeling(memoryId, generation) {
  if (generation === 6 && memoryId === 4 && variable === 0) {
    return randomInt(0, 9);
  }
  const mask = memoryFeelingMasks[memoryId];
  while (true) {
    const raw = randomInt(0, 23);
    if ((mask & (1 << raw)) !== 0) {
      return generation === 8 ? raw + 1 : raw;
    }
  }
}

function canHaveFeelingGen6(memoryId, feeling, variable) {
  if (memoryId === 4 && variable === 0) return feeling >= 0 && feeling < 10;
  return (memoryFeelingMasksGen6[memoryId] & (1 << feeling)) !== 0;
}

